package com.cho2hand.marketplace.controller.media;
import com.cho2hand.marketplace.dto.media.*; import com.cho2hand.marketplace.service.media.MediaService; import jakarta.validation.constraints.Positive; import java.util.List; import org.springframework.http.*; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import org.springframework.web.multipart.MultipartFile;
@RestController @RequestMapping("/api/v1/listings/{listingId}/images") public class MediaController { private final MediaService service; public MediaController(MediaService s){service=s;} @GetMapping public List<MediaResponse> list(@PathVariable @Positive Long listingId){return service.list(listingId);} @GetMapping("/{mediaId}/content") public ResponseEntity<byte[]> content(@PathVariable @Positive Long listingId,@PathVariable @Positive Long mediaId){var content=service.content(listingId,mediaId);return ResponseEntity.ok().contentType(MediaType.parseMediaType(content.contentType())).cacheControl(CacheControl.maxAge(java.time.Duration.ofHours(1)).cachePublic()).body(content.bytes());} @PostMapping(consumes=MediaType.MULTIPART_FORM_DATA_VALUE) @ResponseStatus(HttpStatus.CREATED) public MediaResponse upload(@AuthenticationPrincipal Long userId,@PathVariable @Positive Long listingId,@RequestPart("file") MultipartFile file){return service.upload(userId,listingId,file);} @DeleteMapping("/{mediaId}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@AuthenticationPrincipal Long userId,@PathVariable @Positive Long listingId,@PathVariable @Positive Long mediaId){service.delete(userId,listingId,mediaId);} }
